import{_ as g}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as c,c as p,d as C,e as t,w as e,a as i,b as a,f as n}from"./app-02156c45.js";const _="/blog/assets/blog_image/图腾柱PFC/传统有桥PFC.png",r="/blog/assets/blog_image/图腾柱PFC/双Boost无桥PFC结构.png",d="/blog/assets/blog_image/图腾柱PFC/图腾柱PFC结构.png",f="/blog/assets/blog_image/图腾柱PFC/反向恢复电流.png",h="/blog/assets/blog_image/图腾柱PFC/图腾柱PFC基本结构.png",u="/blog/assets/blog_image/图腾柱PFC/电网电压正半周及负半周示意图.png",P="/blog/assets/blog_image/图腾柱PFC/电网电压正半周时的电流路径.png",F="/blog/assets/blog_image/图腾柱PFC/电网电压正负半周时的电流路径.png",m="/blog/assets/blog_image/图腾柱PFC/公式1.png",b="/blog/assets/blog_image/图腾柱PFC/公式2.png",A="/blog/assets/blog_image/图腾柱PFC/公式3.png",Q="/blog/assets/blog_image/图腾柱PFC/公式4.png",x="/blog/assets/blog_image/图腾柱PFC/公式5.png",D="/blog/assets/blog_image/图腾柱PFC/公式6.png",y="/blog/assets/blog_image/图腾柱PFC/图腾柱PFC的启动电路.png",z="/blog/assets/blog_image/图腾柱PFC/图腾柱PFC功率级典型结构.png",V="/blog/assets/blog_image/图腾柱PFC/AC过零点处的PWM时序处理.png",M="/blog/assets/blog_image/图腾柱PFC/图腾柱PFC的双向AC电流采样波形.png",S="/blog/assets/blog_image/图腾柱PFC/电流环和直流偏置1.png",B="/blog/assets/blog_image/图腾柱PFC/电流环和直流偏置2.png",H="/blog/assets/blog_image/图腾柱PFC/电流环和直流偏置3.png",W="/blog/assets/blog_image/图腾柱PFC/电流环和直流偏置4.png",N={},k=i("h1",{id:"图腾柱pfc-ccm模式的基本工作原理及控制要点分析",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#图腾柱pfc-ccm模式的基本工作原理及控制要点分析","aria-hidden":"true"},"#"),a(" 图腾柱PFC CCM模式的基本工作原理及控制要点分析")],-1),T=i("p",null,"    随着宽禁带器件的发展，图腾柱PFC电路在现今的应用越来越广泛，在需要双向运行的车载OBC中，以及5G基站储能备用电源，便携式储能电源等典型应用中，它是典型的前级运行拓扑。我们有必要对其进行一些基本的分析和总结，方便参考。本文主要分为如下几个部分，对图腾柱PFC电路进行讨论。",-1),E=i("h2",{id:"一-传统pfc的缺点及图腾柱pfc的发展",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#一-传统pfc的缺点及图腾柱pfc的发展","aria-hidden":"true"},"#"),a(" 一．传统PFC的缺点及图腾柱PFC的发展")],-1),v=i("p",null,"    在AC/DC系统中，在节能减排的驱动下，效率要求越来越高。而根据法规，75W以上的AC/DC一定要增加PFC电路，以便让电流波形跟随正弦电压波形，让电网看到的负载就像电阻一样，产生较好的PF和THD。传统有桥PFC由于跨过输入电感的电压极性是经过整流的半波正弦电压，所以极性是固定的，在控制上相对简单，但是其电流路径需要经过两个整流桥二极管，因此效率相对较低，无法适用于大功率电源的需求。",-1),I=i("figure",null,[i("img",{src:_,alt:"图1传统有桥boostPFC结构",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图1传统有桥boostPFC结构")],-1),w=i("p",null,"    为了解决有桥PFC的导通损耗大的问题，演变出了各种无桥PFC结构，其中双Boost无桥PFC是应用比较广泛的一种。",-1),G=i("p",null,"    在如下的结构中，除了减小了整流桥造成的导通损耗之外，其主开关的驱动，由于都是对地的低边驱动，所以相对较容易实施。",-1),L=i("p",null,"    由于增加了交流电压的续流管，DN1,DN2，所以其相应的共模干扰特性会比较好，但是，这无疑会增加电流路径上的器件，从而降低效率和增加复杂性。",-1),R=i("figure",null,[i("img",{src:r,alt:"图2双Boost无桥PFC结构",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图2双Boost无桥PFC结构")],-1),U=i("p",null,"    而在BoostPFC的家族里面，图腾柱PFC是器件更少的，如下图所示，在电流路径上只有2个半功率导体器件，其损耗必然会更小，理论上，其效率必然会更高。",-1),q=i("figure",null,[i("img",{src:d,alt:"图3图腾柱PFC结构",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图3图腾柱PFC结构")],-1),j=i("p",null,"    在介绍图腾柱PFC的缺点前，我们先讨论一下什么是反向恢复电流和反向恢复损耗，如下图4所示，",-1),J=i("p",null,"    当二极管正向导通时，其电流是I+,而当其截止时，二极管电流为接近0的I0，但是当二极管由导通向截止转换时，电流不能立刻变0，而需要一定的恢复时间，在此时间内，电流为下图所示的负值，此部分电流分存储时间和下降时间两部分。反向恢复电荷越大，则反向恢复特性越差。在右侧的图上可以看到，在反向恢复时间内，由于二极管电压由低变高，因此会造成一定的关断损耗，即反向恢复损耗。",-1),O=i("figure",null,[i("img",{src:f,alt:"图4反向恢复电流",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图4反向恢复电流")],-1),K=i("p",null,"    由于上述原因，在很长时间内，图腾柱PFC一直没有得到广泛应用，在上图中，假设S1,S2都是普通的硅mosfet的情况下，让系统运行在CCM硬开关模式下，在AC正半周期，电感电流一直为正，S1,S2以互补模式运行，为了避免直通，二者之间留有死区。当S2关断S1开通之前，电感电流通路是S2的体二极管，当结束死区，S1开通时，S2两端的电压需要立即由接近0V变到Vo，从而体二极管由导通状态变到阻断状态。而传统的硅mosfet的体二极管反向恢复特性是非常差的，所以，在这个过程中必然会导致比较大的反向恢复损耗，同时S2会产生较大的关断振荡电压。当AC电压为负时的情况类似，S1会产生较大的震荡电压及反向恢复损耗。",-1),X=i("p",null,"    为了解决硬开关模式下高压mosfet体二极管导致的这个问题，传统的图腾柱PFC多运行于CRM模式，因此限制了其工作功率范围在较低的级别，且由于开关损耗问题不能处于较高运行频率下。",-1),Y=i("p",null,"    随着宽禁带器件的发展，如氮化镓GaN，及SiC碳化硅,通过在系统中引入两个高频宽禁带器件替换原有的图腾柱PFC中的mosfet组成的S1,S2快管，由于宽禁带器件本身开关损耗较小，且体二极管具有接近于0的反向恢复电荷Qrr，则可以使他们很好的运行于CCM硬开关模式下，且处于较高的频率，使得其应用范围得到了较大的发展。",-1),Z=i("h2",{id:"二-图腾柱pfc的稳态基本运行原理分析",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#二-图腾柱pfc的稳态基本运行原理分析","aria-hidden":"true"},"#"),a(" 二.图腾柱PFC的稳态基本运行原理分析")],-1),$=i("p",null,"    如下图5是基于宽禁带器件的图腾柱PFC的基本电路功率级结构，其中，GaN-FETQ3和Q4和电感构成了一个同步整流Boost电路，工作于系统开关频率f_PWM下，Q1和Q2是普通的mosfet，工作于电网频率下f_LINE，并联在Q1,Q2上的肖特基二极管用于进一步改善系统效率。",-1),ii=i("figure",null,[i("img",{src:h,alt:"图5图腾柱PFC基本结构",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图5图腾柱PFC基本结构")],-1),ai=i("figure",null,[i("img",{src:u,alt:"图6电网电压正半周及负半周示意图",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图6电网电压正半周及负半周示意图")],-1),ti=i("p",null,"    当电网AC电压为正时，Q4是主控制开关，其占空比为D,Q3为续流管开关，其占空比为1-D,二者的PWM驱动波形为互补模式PWM,中间留有死区，控制环路用于控制Q4的占空比D,在此阶段下，慢管Q2会一直导通，且电感电流为正，在上图中是向右。如下图7所示，给出了在AC正半周时的电感储能和续流路径。",-1),oi=i("figure",null,[i("img",{src:P,alt:"图7电网电压正半周时的电流路径",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图7电网电压正半周时的电流路径")],-1),ei=i("p",null,"    当电网AC电压为负时，Q3为主控制开关，其占空比为D,Q4为续流管开关，其占空比为1-D,二者的PWM驱动波形依然为互补模式PWM,中间留有死区，控制环路用于控制Q3的占空比D，在此阶段下，慢管Q1会一直导通，且电感电流为负，在图8中是向左的方向。",-1),ni=i("figure",null,[i("img",{src:F,alt:"图8电网电压正负半周时的电流路径",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图8电网电压正负半周时的电流路径")],-1),si=n('<p>    大家如果注意到，在不同的极性的AC电压周期中，Q3和Q4的功能是发生交换的，而电感电流的方向也是发生变化的。</p><h2 id="三-图腾柱pfc的典型器件计算" tabindex="-1"><a class="header-anchor" href="#三-图腾柱pfc的典型器件计算" aria-hidden="true">#</a> 三.图腾柱PFC的典型器件计算</h2><p>    为了计算主要器件的规格，我们做一些条件设定，输入电压Vin为电网电压115V-230VAC(50-60Hz)，输出电压Vout为400VDC,功率Pout设为4kW，开关频率fsw为100kHz，主开关的占空比为D,这里，我们通过公式及分析来计算boost电感和输出电容的值。</p><p>    一般来说，我们希望电感的纹波处在20%左右的电感峰值电流值，电感电流即系统输入电流，而峰值电流在输入电压最低且满载功率时发生，即110V处，根据电感工作的基本关系式，如下式，</p><figure><img src="'+m+'" alt="公式1" tabindex="0" loading="lazy"><figcaption>公式1</figcaption></figure><figure><img src="'+b+'" alt="公式2" tabindex="0" loading="lazy"><figcaption>公式2</figcaption></figure><p>    可以推导出如下公式3，</p><figure><img src="'+A+'" alt="公式3" tabindex="0" loading="lazy"><figcaption>公式3</figcaption></figure><p>    最小电压Vin_min为110VAC,经计算，电感量为83uH，考虑满载时的情况，取一定的裕量，电感设为150uH.</p><p>    输出电容的取值主要取决于PFC的Hold-Up时间Thold-up及输出纹波电压Vripple的大小，这里，我们假定输出纹波电压为10VDC,输出电压为400VDC,则根据电容储能的基本公式，如下，C为电容值，Vc为电容上的电压，</p><figure><img src="'+Q+'" alt="公式4" tabindex="0" loading="lazy"><figcaption>公式4</figcaption></figure><p>    可以推导出以下公式，</p><figure><img src="'+x+'" alt="公式5" tabindex="0" loading="lazy"><figcaption>公式5</figcaption></figure><p>    同时，输出电容还需要满足输出电压纹波10V的限制，由此可得到如下公式，</p><figure><img src="'+D+'" alt="公式6" tabindex="0" loading="lazy"><figcaption>公式6</figcaption></figure><p>    我们假定输出Hold-up时间为一个AC周期，即60Hz对应的16.6mS，则可以计算出输出电容应该为2653uF，因此可以取5个560uF电容并联。</p><h2 id="四-图腾柱pfc的启动过程分析" tabindex="-1"><a class="header-anchor" href="#四-图腾柱pfc的启动过程分析" aria-hidden="true">#</a> 四．图腾柱PFC的启动过程分析</h2><p>    由于启动系统时，若直接开启Boost，由于输出电压是0V,需要以大电流给电容充电，则功率器件会产生很大的电流应力，从而损坏开关，因此一般通过在交流侧正端放置整流二极管配合慢管桥臂的体二极管实现对输出容电压的预充电，如图9所示，在AC为正时开始启动输出预充电过程，则D1和Q4体二极管导通，同时为了限制充电电流应力，则通过Relay让串联在回路中的热敏电阻起作用。</p><figure><img src="'+y+'" alt="图9图腾柱PFC的启动电路" tabindex="0" loading="lazy"><figcaption>图9图腾柱PFC的启动电路</figcaption></figure>',19),li=n('<p>    类似的，如果在AC为负时开启预充电电路，则通过D2和Q3的体二极管导通进行预充电。当预充电结束后，通过Relay短路热敏电阻。</p><h2 id="五-ccm图腾柱pfc的控制要点分析" tabindex="-1"><a class="header-anchor" href="#五-ccm图腾柱pfc的控制要点分析" aria-hidden="true">#</a> 五.CCM图腾柱PFC的控制要点分析</h2><h3 id="a-ac电压过零点尖峰电流" tabindex="-1"><a class="header-anchor" href="#a-ac电压过零点尖峰电流" aria-hidden="true">#</a> A: AC电压过零点尖峰电流</h3><p>    在CCM图腾柱PFC电路中，一个典型的控制问题是AC电压过零点切换，这会导致较大的电流尖峰。这个问题主要是由于开关的导通顺序，及慢管的体二极管桥臂的反向恢复电荷，寄生输出电容条件下，AC过零时，主开关和续流开关的突然切换角色造成，这会导致增加THD值，且使得PF值变差，其本质上是对应慢管的寄生输出电容Coss放电。</p><figure><img src="'+z+'" alt="图10图腾柱PFC功率级典型结构" tabindex="0" loading="lazy"><figcaption>图10图腾柱PFC功率级典型结构</figcaption></figure>',5),gi=i("p",null,"    如图10，我们再次将图腾柱PFC典型功率电路放置在这里，我们分析两种情况，当AC电压从正到负切换时，及AC电压从负到正切换时。",-1),ci=i("p",null,"    当AC电压处在正半周期时，且接近AC过零点时，Q4为主开关，由于输入电压很小，所以其占空比会达到接近100%（Q3占空比接近0），而Q2在此半周期一直导通，当AC电压过渡到负半周期时，Q3为主开关，由于输入电压很小，所以其占空比接近为100%（Q4占空比接近0），此阶段Q1会由关断变为导通，则当Q3一导通时，Q1的寄生输出电容Coss会很快放电，产生反向电感电流，因此会造成很大的过零切换的电流尖峰。",-1),pi=i("p",null,"    类似的，当AC电压处在负半周期时，且接近AC过零点时，Q3为主开关，由于输入电压很小，所以其占空比会达到接近100%（Q4占空比接近0），而Q1在此半周期一直导通，当AC电压过渡到正半周期时，Q4为主开关，由于输入电压很小，所以其占空比接近为100%（Q3占空比接近0），此阶段Q2由关断变为导通，则当Q4导通时，Q2的寄生输出电容Coss会很快放电，产生正电电感电流，因此也会造成很大的过零切换的电流尖峰。",-1),Ci=i("p",null,"    由于在关断状态下，慢速桥臂的漏极电压非常高，达到输出电压400V左右，因此其在大占空比下放电电流会非常大。此时由于续流管开关占空比接近0，所以不会产生输出电容放电。",-1),_i=i("p",null,"    一般来说，推荐如下的AC过零点驱动方式，如下图11所示，",-1),ri=i("figure",null,[i("img",{src:V,alt:"图11 AC过零点处的PWM时序处理",tabindex:"0",loading:"lazy"}),i("figcaption",null,"图11 AC过零点处的PWM时序处理")],-1),di=n('<p>    当系统检测到接近过零点时（从AC负到正或者从AC正到负），则控制器关闭所有的控制开关管Q1,Q2,Q3,Q4，电感电流通过开关管的体二极管流过续流，避免噪声对门级驱动信号的影响。当结束这部分窗口时间时（检测到可靠过零），主开关管先进行软起动过程，逐步增加占空比D，此时续流管通过体二极管续流，经过若干周期后，续流管也进行逐步的软起动。当软起动的占空比等于闭环控制的占空比时，则结束软起动，闭环控制起作用。</p><p>    举例来说，从AC为正向AC为负转变时，系统检测到这一窗口后，关闭Q1-Q4,当检测到AC可靠过零后，主开关Q3开始以很小的占空比开始软起动，在软起动过程中，续流管Q4并未开启，而是通过体二极管续流，此阶段中，慢管Q1寄生输出电容在主开关导通时逐渐放电，从而最终打开Q1门级，接着对续流管Q3进行软起动，避免在续流管占空比大时造成尖峰电流。</p><p>    经过这样去处理门级驱动时序，则可以很好的减小过零点造成的电流尖峰，提高PF值，降低THD.</p><h3 id="b-如何可靠的检测ac过零点" tabindex="-1"><a class="header-anchor" href="#b-如何可靠的检测ac过零点" aria-hidden="true">#</a> B: 如何可靠的检测AC过零点</h3><p>    一般情况下，如果由于噪声使得控制器检测到AC过零，例如从AC正到AC负，则Q3占空比从0突然就变到100%，此时由于事实上还处在AC正半周期，所以Q2还在导通状态，所以这会导致输出电压Vout经过电感直接短路到地电压，这势必会在电感上产生很大的尖峰电流，从而可能导致功率器件烧坏。</p><p>    正确推荐的方式是，如图11所示，当系统检测到接近AC过零时（例如AC从正到负），就关闭所有控制开关，从而阻止了输出电容电压放电，当控制器真正多次检测到AC过零后，系统开始对主开关Q3进行软起动。</p><p>    这样就可以避免由于噪声干扰导致的错误判断的AC过零点，从而提前开启主开关，从而由于输出电容反向放电，从而产生很大的尖峰电流。</p><h3 id="c-软起动时续流管状态" tabindex="-1"><a class="header-anchor" href="#c-软起动时续流管状态" aria-hidden="true">#</a> C: 软起动时续流管状态</h3><p>    当软起动时，系统控制环路正在逐步建立，主开关占空比很小，因为续流管和主开关为互补模式，所以其占空比1-D很大，如果在主开关做软起动时，也同时开启续流管，且相应慢管也处于开通状态时，则会产生输出电容放电。所以，我们如图11，在主开关软起动时，将续流管开关设置为关闭状态，经过若干周期后，主开关的占空比也变大了，续流管也开始软起动，因此可以避免续流管大占空比1-D导致输出电容电压放电。</p><h3 id="d-参考电压及控制环路极性的问题" tabindex="-1"><a class="header-anchor" href="#d-参考电压及控制环路极性的问题" aria-hidden="true">#</a> D: 参考电压及控制环路极性的问题</h3><p>    在图腾柱PFC电路中，由于根据所处的AC电压极性不同，其采样电流方向也不会相同，一般通过传感器件获得电感电流波形，如图12，由于处理器比较方便处理正电压，所以在采样电流上叠加一个直流偏置电压DCoffset，这和传统PFC的采样电流波形是不同的，传统PFC采样波形由于存在整流桥，采样电流是正向的电流，且不需要叠加直流分量。</p><figure><img src="'+M+'" alt="图12 图腾柱PFC的双向AC电流采样波形" tabindex="0" loading="lazy"><figcaption>图12 图腾柱PFC的双向AC电流采样波形</figcaption></figure>',12),fi=n('<p>    当处在正AC周期中时，可以像传统PFC一样得到电流参考，但是需要叠加相应的直流偏置，如下式所示，作为电流环的参考信号</p><figure><img src="'+S+'" alt="电流环和直流偏置1" tabindex="0" loading="lazy"><figcaption>电流环和直流偏置1</figcaption></figure><p>    从而，电流环误差就由参考减去反馈得到，如下式所示，</p><figure><img src="'+B+'" alt="电流环和直流偏置2" tabindex="0" loading="lazy"><figcaption>电流环和直流偏置2</figcaption></figure><p>    当处在负AC电压周期中时，参考电压从图12上得知，由下式决定，</p><figure><img src="'+H+'" alt="电流环和直流偏置3" tabindex="0" loading="lazy"><figcaption>电流环和直流偏置3</figcaption></figure><p>    因为反馈信号是反比于真实电流信号的，也就是说，反馈信号越大，则对应采样的电流信号越小，所以在负AC周期的电流环中，需要将控制极性翻转一下，如下式所示，</p><figure><img src="'+W+'" alt="电流环和直流偏置4" tabindex="0" loading="lazy"><figcaption>电流环和直流偏置4</figcaption></figure><p>    这样处理之后，参考电压就可以满足整个AC周期的控制要求。</p><h3 id="e-输入电压突然下掉造成的问题" tabindex="-1"><a class="header-anchor" href="#e-输入电压突然下掉造成的问题" aria-hidden="true">#</a> E: 输入电压突然下掉造成的问题</h3><p>    当图腾柱PFC电路正在运行中，输入电压突然发生下掉，此时由于系统不能立即检测到电压下掉这个事情发生，因此会造成一系列的问题。举一个最差的情况，当输入电压处在峰值时，此时主开关占空比最小，而续流管占空比1-D最大，当电压下掉时（以AC为正时为例），输出电容电压通过续流管Q3向电感侧进行反向放电，注意此时Q2是一直导通的，所以这个放电会产生一些严重的问题。首先，输出电压放电会导致无法满足Hold-Up时间要求，其次，反向放电会造成较大的尖峰电流。</p><p>    所以，在控制上需要对输入电压下掉进行快速检测，或者通过对反向电流进行检测，从而捕获这一事件，当系统知道这一事件后，就可以做出一些措施。</p><p>    大家可以注意一下，当处在正半周AC电压时，正常电流是从电感流向输出侧，发生输出电容放电时电流从输出侧流向电感侧。而处在负半周AC电压时，正常电流是从输出侧流向电感侧，则发生输出电容放电时，反向电流是从电感侧流向输出侧。所以，通过检测和正常电流不同方向的电流尖峰就可以捕获这一特殊事件。</p><p>    当检测到这一事件后，一般推荐将所有开关全部关闭，以此避免上述两个问题的出现，尤其是输出电容放电。</p><h3 id="f-电压下掉恢复后的处理" tabindex="-1"><a class="header-anchor" href="#f-电压下掉恢复后的处理" aria-hidden="true">#</a> F: 电压下掉恢复后的处理</h3><p>    对于传统的PFC电路，当检测到电压下掉恢复后，在任何时刻重新开启控制开关都是可以的，但是在图腾柱PFC电路中，这一点有些不同。举一个极端的例子，当输入电压在峰值时恢复了（以正AC峰值为例），则主控管Q4的稳态占空比达到最小，而续流管Q3的占空比1-D达到最大，此时若开启续流管，则又面临输出电容的放电大电流尖峰出现。所以一般的，推荐以一个像AC输入电压过零时一样的固定的方式重新恢复电路控制开关的导通，比如，在过零处恢复电路，并且首先开启主开关，进行主开关的软起动控制，这样就可以避免随机恢复电路造成的输出电容放电电流尖峰。</p><p>    以上，我们首先通过分析图腾柱PFC电路的发展，接着分析了图腾柱PFC在CCM模式的基本运行原理及主要无源器件输入电感和输出电容计算，最后讨论了若干CCM模式图腾柱PFC控制中的一些要点，通过本文可以对图腾柱PFC的一些主要问题做一些基本参考。</p><h2 id="参考文献" tabindex="-1"><a class="header-anchor" href="#参考文献" aria-hidden="true">#</a> 参考文献：</h2><ul><li><p>Control challenges in a totem-pole PFC</p></li><li><p>1.5 kW Single Phase CCM Totem-Pole PFCUsing 650V SiC Cascodes</p></li></ul><div class="hint-container tip"><p class="hint-container-title">提示</p><p>本文转载于“电源漫谈”的《图腾柱PFC CCM模式的基本工作原理及控制要点分析》。</p></div><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> <strong>参考资料</strong></h2>',21),hi={href:"https://mp.weixin.qq.com/s/u-faJAQHGTPD3AycjLas6A",target:"_blank",rel:"noopener noreferrer"};function ui(Pi,Fi){const o=s("center"),l=s("ExternalLinkIcon");return c(),p("div",null,[k,T,C(" more "),E,v,I,t(o,null,{default:e(()=>[a("图1 传统有桥boostPFC结构")]),_:1}),w,G,L,R,t(o,null,{default:e(()=>[a("图2 双Boost无桥PFC结构")]),_:1}),U,q,t(o,null,{default:e(()=>[a("图3 图腾柱PFC结构")]),_:1}),j,J,O,t(o,null,{default:e(()=>[a("图4 反向恢复电流")]),_:1}),K,X,Y,Z,$,ii,t(o,null,{default:e(()=>[a("图5 图腾柱PFC基本结构")]),_:1}),ai,t(o,null,{default:e(()=>[a("图6 电网电压正半周及负半周示意图")]),_:1}),ti,oi,t(o,null,{default:e(()=>[a("图7 电网电压正半周时的电流路径")]),_:1}),ei,ni,t(o,null,{default:e(()=>[a("图8 电网电压正负半周时的电流路径")]),_:1}),si,t(o,null,{default:e(()=>[a("图9 图腾柱PFC的启动电路")]),_:1}),li,t(o,null,{default:e(()=>[a("图10 图腾柱PFC功率级典型结构")]),_:1}),gi,ci,pi,Ci,_i,ri,t(o,null,{default:e(()=>[a("图11 AC过零点处的PWM时序处理")]),_:1}),di,t(o,null,{default:e(()=>[a("图12 图腾柱PFC的双向AC电流采样波形")]),_:1}),fi,i("p",null,[i("a",hi,[a("图腾柱PFC CCM模式的基本工作原理及控制要点分析"),t(l)])])])}const Ai=g(N,[["render",ui],["__file","1005.图腾柱PFC CCM模式的基本工作原理及控制要点分析.html.vue"]]);export{Ai as default};
